import{_ as o,o as t,c as r,ag as a}from"./chunks/framework.DGzMGr_a.js";const h=JSON.parse('{"title":"浏览器存储：Cookie / localStorage / sessionStorage / IndexedDB","description":"","frontmatter":{"title":"浏览器存储：Cookie / localStorage / sessionStorage / IndexedDB","difficulty":"medium","tags":["存储","Cookie","localStorage","IndexedDB"],"estimate":20},"headers":[],"relativePath":"domains/browser/qa/qa-06-web-storage.md","filePath":"domains/browser/qa/qa-06-web-storage.md","lastUpdated":1783504823000}'),l={name:"domains/browser/qa/qa-06-web-storage.md"};function d(i,e,s,n,c,g){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="问答-06-进阶-浏览器存储-cookie-localstorage-sessionstorage-indexeddb" tabindex="-1">问答 06（进阶）：浏览器存储：Cookie / localStorage / sessionStorage / IndexedDB <a class="header-anchor" href="#问答-06-进阶-浏览器存储-cookie-localstorage-sessionstorage-indexeddb" aria-label="Permalink to &quot;问答 06（进阶）：浏览器存储：Cookie / localStorage / sessionStorage / IndexedDB&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>浏览器提供了多种客户端存储，Cookie、localStorage、sessionStorage、IndexedDB 各自的容量、作用域、生命周期、同步/异步、随请求发送等有什么区别？分别适合什么场景？</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>四者对比</strong></p><table tabindex="0"><thead><tr><th>维度</th><th>Cookie</th><th>localStorage</th><th>sessionStorage</th><th>IndexedDB</th></tr></thead><tbody><tr><td>容量</td><td>每个域约 4KB，条数有限</td><td>约 5-10MB / 源</td><td>约 5-10MB / 源</td><td>几十 MB 到几 GB（浏览器动态配额）</td></tr><tr><td>生命周期</td><td>Expires/Max-Age 控制，或会话级</td><td>永久（除非清除）</td><td>tab 关闭即销毁</td><td>永久</td></tr><tr><td>作用域</td><td>域 + Path，可跨子域（Domain 属性）</td><td>同源（协议+域+端口）</td><td>同源 + 同 tab</td><td>同源</td></tr><tr><td>随请求发送</td><td>是（同源自动带，跨源受 SameSite 限制）</td><td>否</td><td>否</td><td>否</td></tr><tr><td>访问方式</td><td><code>document.cookie</code>（同步字符串）</td><td><code>localStorage.setItem</code> 同步</td><td>同 localStorage</td><td>异步（Promise / 事件）</td></tr><tr><td>类型</td><td>字符串</td><td>字符串（需 JSON 序列化）</td><td>字符串</td><td>任何结构化数据（对象、Blob、File）</td></tr><tr><td>Web Worker 可用</td><td>否（无 document）</td><td>否</td><td>否</td><td>是</td></tr></tbody></table><p><strong>Cookie</strong></p><ul><li>唯一会被浏览器<strong>自动带到请求</strong>的存储，因此用于登录态、CSRF token。</li><li>每次请求都会带上，容量放不下大数据。</li><li>安全属性：<code>HttpOnly</code>、<code>Secure</code>、<code>SameSite</code>、<code>Domain</code>、<code>Path</code>、<code>Expires</code>/<code>Max-Age</code>。</li><li>会拖累性能：静态资源域名带上大 cookie 会浪费带宽（所以生产上把静态资源放独立 cookie-free 域名或走 CDN）。</li></ul><p><strong>localStorage</strong></p><ul><li>简单键值存储，同步 API，容易用。</li><li>只能存字符串（对象要 <code>JSON.stringify</code> / <code>JSON.parse</code>）。</li><li>同步读写会阻塞主线程，避免存大量数据。</li><li>无过期机制，需要自己管理。</li><li>适合：用户偏好、UI 状态、简单缓存。</li></ul><p><strong>sessionStorage</strong></p><ul><li>与 localStorage API 相同，但<strong>限当前 tab 且 tab 关闭失效</strong>。</li><li>页内 SPA 状态、单次流程数据（多步表单）合适。</li></ul><p><strong>IndexedDB</strong></p><ul><li>结构化的、事务型、大容量的浏览器数据库。</li><li>支持索引、游标查询、Blob 存储。</li><li>异步 API，不阻塞主线程；也支持 Web Worker。</li><li>适合：离线数据、复杂前端缓存、PWA。</li><li>原生 API 相对繁琐，一般用封装库如 <code>idb</code> / <code>Dexie.js</code> / <code>localForage</code>。</li></ul><p><strong>其它相关存储</strong></p><ul><li><strong>Cache Storage</strong>：Service Worker 用来缓存 Request/Response，做离线。</li><li><strong>File System Access API</strong>：Chrome 支持，让页面读写用户本地文件。</li><li><strong>Cookie Store API</strong>：<code>document.cookie</code> 的现代异步替代。</li></ul><h2 id="追问-1-localstorage-和-cookie-存-token-各有什么优缺点" tabindex="-1">追问 1：localStorage 和 Cookie 存 Token 各有什么优缺点？ <a class="header-anchor" href="#追问-1-localstorage-和-cookie-存-token-各有什么优缺点" aria-label="Permalink to &quot;追问 1：localStorage 和 Cookie 存 Token 各有什么优缺点？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>Cookie（HttpOnly + Secure + SameSite）</strong><ul><li>优点：JS 拿不到（防 XSS 窃取），浏览器自动带，服务端易验证。</li><li>缺点：默认会被 CSRF 利用，需要 <code>SameSite=Lax/Strict</code> 或 CSRF token 缓解；跨站请求需要 <code>SameSite=None; Secure</code>。</li></ul></li><li><strong>localStorage 存 Token</strong><ul><li>优点：不会自动带，无 CSRF；请求头由前端主动设置（<code>Authorization: Bearer &lt;token&gt;</code>）。</li><li>缺点：JS 可读，一旦有 XSS 就能被窃取；无自动过期；多 tab 需要广播刷新。</li></ul></li><li>现代推荐： <ul><li>Web 强安全场景：HttpOnly Cookie + SameSite + CSRF token / Origin 校验。</li><li>SPA + 后端 API 分离：Refresh Token 放 HttpOnly Cookie，短期 Access Token 放内存（不落地）。</li><li>避免把长期 Token 明文存 localStorage。</li></ul></li></ul><h2 id="追问-2-为什么-localstorage-是同步阻塞的-可能有什么坑" tabindex="-1">追问 2：为什么 localStorage 是同步阻塞的？可能有什么坑？ <a class="header-anchor" href="#追问-2-为什么-localstorage-是同步阻塞的-可能有什么坑" aria-label="Permalink to &quot;追问 2：为什么 localStorage 是同步阻塞的？可能有什么坑？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>localStorage 的设计早于 Web Worker、Service Worker，API 是同步的字符串接口。数据写入需要立刻落盘（浏览器实现里可能有内存缓冲）。</li><li>坑： <ul><li><strong>大量写入会卡主线程</strong>，动辄十几毫秒到上百毫秒；页面动画会掉帧。</li><li><strong>配额被填满</strong>会抛 <code>QuotaExceededError</code>，需要 try/catch。</li><li><strong>多 tab 竞争</strong>：同源多个 tab 都在写同一 key 可能覆盖；用 <code>storage</code> 事件监听变化并做同步。</li><li><strong>无原子事务</strong>，多字段更新不能保证一致性；写到一半崩溃可能不一致。</li></ul></li><li>大数据 / 高频写：转 IndexedDB。</li></ul><h2 id="追问-3-如果要在多个-tab-之间实时同步某个状态-有哪些方案" tabindex="-1">追问 3：如果要在多个 tab 之间实时同步某个状态，有哪些方案？ <a class="header-anchor" href="#追问-3-如果要在多个-tab-之间实时同步某个状态-有哪些方案" aria-label="Permalink to &quot;追问 3：如果要在多个 tab 之间实时同步某个状态，有哪些方案？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong><code>storage</code> 事件</strong>：<code>localStorage</code> / <code>sessionStorage</code> 改动时同源其它 tab 会收到 <code>window.addEventListener(&#39;storage&#39;, ...)</code>（当前 tab 不会收到自己写入的事件）。适合简单同步。</li><li><strong>BroadcastChannel</strong>：<code>new BroadcastChannel(&#39;room&#39;).postMessage(data)</code>，同源 tab / iframe / worker 都能收到，API 直观。</li><li><strong>SharedWorker</strong>：多个 tab 连到同一个 SharedWorker，通过 <code>MessagePort</code> 通信；能维持共享状态。</li><li><strong>Service Worker</strong>：也能作为消息中转（<code>clients.matchAll()</code> + <code>postMessage</code>），并且能持久后台。</li><li><strong>服务端推</strong>：WebSocket / SSE，让服务端广播（跨端更好，代价是要连服务端）。</li><li>生产上常用组合：BroadcastChannel 做 UI 同步 + Service Worker 做离线协调。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/domains/browser/RESOURCES">浏览器 &amp; 网络 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://developer.mozilla.org/en-US/docs/Web/API/Web_Storage_API" target="_blank" rel="noreferrer">MDN: Web Storage API</a>：localStorage / sessionStorage</li><li><a href="https://www.w3.org/TR/IndexedDB/" target="_blank" rel="noreferrer">IndexedDB API (W3C)</a>：大容量客户端存储规范</li><li><a href="https://developer.mozilla.org/en-US/docs/Web/HTTP/Guides/Cookies" target="_blank" rel="noreferrer">MDN: Using HTTP cookies</a>：Cookie 存储机制</li></ul>',28)])])}const k=o(l,[["render",d]]);export{h as __pageData,k as default};
